{"command": "cat > root/snake-game/game.js << 'EOF'
/**
 * 贪吃蛇游戏 - JavaScript 实现
 * 使用 HTML5 Canvas 和面向对象编程
 */

// 游戏常量
const GRID_SIZE = 20;
const CANVAS_WIDTH = 600;
const CANVAS_HEIGHT = 600;
const GRID_WIDTH = CANVAS_WIDTH / GRID_SIZE;
const GRID_HEIGHT = CANVAS_HEIGHT / GRID_SIZE;

// 游戏状态
const GAME_STATE = {
    MENU: 'menu',
    PLAYING: 'playing',
    PAUSED: 'paused',
    GAME_OVER: 'game_over'
};

// 方向常量
const DIRECTION = {
    UP: { x: 0, y: -1 },
    DOWN: { x: 0, y: 1 },
    LEFT: { x: -1, y: 0 },
    RIGHT: { x: 1, y: 0 }
};

// 颜色常量
const COLORS = {
    SNAKE_HEAD: '#4CAF50',
    SNAKE_BODY: '#8BC34A',
    FOOD: '#FF5722',
    BACKGROUND: '#2C3E50',
    GRID: '#34495E',
    TEXT: '#ECF0F1'
};

class Snake {
    constructor() {
        this.reset();
    }

    reset() {
        // 蛇初始位置在画布中央
        this.segments = [
            { x: Math.floor(GRID_WIDTH / 2), y: Math.floor(GRID_HEIGHT / 2) },
            { x: Math.floor(GRID_WIDTH / 2) - 1, y: Math.floor(GRID_HEIGHT / 2) },
            { x: Math.floor(GRID_WIDTH / 2) - 2, y: Math.floor(GRID_HEIGHT / 2) }
        ];
        this.direction = DIRECTION.RIGHT;
        this.nextDirection = DIRECTION.RIGHT;
        this.growPending = 0;
    }

    get head() {
        return this.segments[0];
    }

    update() {
        // 更新方向
        this.direction = this.nextDirection;

        // 计算新的头部位置
        const newHead = {
            x: this.head.x + this.direction.x,
            y: this.head.y + this.direction.y
        };

        // 添加新的头部
        this.segments.unshift(newHead);

        // 如果不需要增长，移除尾部
        if (this.growPending > 0) {
            this.growPending--;
        } else {
            this.segments.pop();
        }
    }

    grow(amount = 1) {
        this.growPending += amount;
    }

    setDirection(newDirection) {
        // 防止直接反向移动（例如：向右移动时不能立即向左转）
        if (
            (newDirection === DIRECTION.LEFT && this.direction !== DIRECTION.RIGHT) ||
            (newDirection === DIRECTION.RIGHT && this.direction !== DIRECTION.LEFT) ||
            (newDirection === DIRECTION.UP && this.direction !== DIRECTION.DOWN) ||
            (newDirection === DIRECTION.DOWN && this.direction !== DIRECTION.UP)
        ) {
            this.nextDirection = newDirection;
        }
    }

    checkSelfCollision() {
        const head = this.head;
        // 检查头部是否与身体其他部分碰撞（跳过头部本身）
        for (let i = 1; i < this.segments.length; i++) {
            if (head.x === this.segments[i].x && head.y === this.segments[i].y) {
                return true;
            }
        }
        return false;
    }

    checkWallCollision() {
        const head = this.head;
        return (
            head.x < 0 || head.x >= GRID_WIDTH ||
            head.y < 0 || head.y >= GRID_HEIGHT
        );
    }
}

class Food {
    constructor() {
        this.position = { x: 0, y: 0 };
        this.respawn();
    }

    respawn(snakeSegments = []) {
        let newPosition;
        let collision;

        do {
            collision = false;
            newPosition = {
                x: Math.floor(Math.random() * GRID_WIDTH),
                y: Math.floor(Math.random() * GRID_HEIGHT)
            };

            // 检查是否与蛇身重叠
            for (const segment of snakeSegments) {
                if (segment.x === newPosition.x && segment.y === newPosition.y) {
                    collision = true;
                    break;
                }
            }
        } while (collision);

        this.position = newPosition;
    }
}

class Game {
    constructor() {
        this.canvas = document.getElementById('game-canvas');
        this.ctx = this.canvas.getContext('2d');
        this.snake = new Snake();
        this.food = new Food();
        this.state = GAME_STATE.MENU;
        this.score = 0;
        this.highScore = localStorage.getItem('snakeHighScore') || 0;
        this.gameSpeed = 150; // 毫秒
        this.gameLoop = null;

        this.init();
    }

    init() {
        // 更新UI
        this.updateScore();
        document.getElementById('high-score').textContent = this.highScore;

        // 绑定事件
        this.bindEvents();

        // 绘制初始状态
        this.draw();
    }

    bindEvents() {
        // 键盘控制
        document.addEventListener('keydown', (e) => {
            switch (e.key) {
                case 'ArrowUp':
                    this.snake.setDirection(DIRECTION.UP);
                    e.preventDefault();
                    break;
                case 'ArrowDown':
                    this.snake.setDirection(DIRECTION.DOWN);
                    e.preventDefault();
                    break;
                case 'ArrowLeft':
                    this.snake.setDirection(DIRECTION.LEFT);
                    e.preventDefault();
                    break;
                case 'ArrowRight':
                    this.snake.setDirection(DIRECTION.RIGHT);
                    e.preventDefault();
                    break;
                case ' ':
                    if (this.state === GAME_STATE.PLAYING) {
                        this.pause();
                    } else if (this.state === GAME_STATE.PAUSED) {
                        this.resume();
                    }
                    e.preventDefault();
                    break;
                case 'Enter':
                    if (this.state === GAME_STATE.MENU || this.state === GAME_STATE.GAME_OVER) {
                        this.start();
                    }
                    e.preventDefault();
                    break;
            }
        });

        // 按钮控制
        document.getElementById('start-btn').addEventListener('click', () => this.start());
        document.getElementById('pause-btn').addEventListener('click', () => {
            if (this.state === GAME_STATE.PLAYING) {
                this.pause();
            } else if (this.state === GAME_STATE.PAUSED) {
                this.resume();
            }
        });
        document.getElementById('reset-btn').addEventListener('click', () => this.reset());
        document.getElementById('restart-btn').addEventListener('click', () => this.start());
    }

    start() {
        if (this.state === GAME_STATE.PLAYING) return;

        this.state = GAME_STATE.PLAYING;
        this.snake.reset();
        this.food.respawn(this.snake.segments);
        this.score = 0;
        this.updateScore();

        // 隐藏游戏结束界面
        document.getElementById('game-over').style.display = 'none';

        // 开始游戏循环
        if (this.gameLoop) clearInterval(this.gameLoop);
        this.gameLoop = setInterval(() => this.update(), this.gameSpeed);

        // 更新按钮状态
        this.updateButtonStates();
    }

    pause() {
        if (this.state !== GAME_STATE.PLAYING) return;

        this.state = GAME_STATE.PAUSED;
        clearInterval(this.gameLoop);
        this.gameLoop = null;

        // 绘制暂停状态
        this.drawPauseScreen();
        this.updateButtonStates();
    }

    resume() {
        if (this.state !== GAME_STATE.PAUSED) return;

        this.state = GAME_STATE.PLAYING;
        this.gameLoop = setInterval(() => this.update(), this.gameSpeed);
        this.updateButtonStates();
    }

    reset() {
        this.state = GAME_STATE.MENU;
        this.snake.reset();
        this.food.respawn(this.snake.segments);
        this.score = 0;
        this.updateScore();

        if (this.gameLoop) {
            clearInterval(this.gameLoop);
            this.gameLoop = null;
        }

        // 隐藏游戏结束界面
        document.getElementById('game-over').style.display = 'none';

        this.draw();
        this.updateButtonStates();
    }

    gameOver() {
        this.state = GAME_STATE.GAME_OVER;
        clearInterval(this.gameLoop);
        this.gameLoop = null;

        // 更新最高分
        if (this.score > this.highScore) {
            this.highScore = this.score;
            localStorage.setItem('snakeHighScore', this.highScore);
            document.getElementById('high-score').textContent = this.highScore;
        }

        // 显示游戏结束界面
        document.getElementById('final-score').textContent = this.score;
        document.getElementById('game-over').style.display = 'flex';

        this.updateButtonStates();
    }

    update() {
        // 更新蛇的位置
        this.snake.update();

        // 检查碰撞
        if (this.snake.checkWallCollision() || this.snake.checkSelfCollision()) {
            this.gameOver();
            return;
        }

        // 检查是否吃到食物
        if (this.snake.head.x === this.food.position.x && this.snake.head.y === this.food.position.y) {
            this.snake.grow();
            this.score += 10;
            this.updateScore();
            this.food.respawn(this.snake.segments);

            // 每得100分增加游戏速度
            if (this.score % 100 === 0 && this.gameSpeed > 50) {
                this.gameSpeed -= 10;
                clearInterval(this.gameLoop);
                this.gameLoop = setInterval(() => this.update(), this.gameSpeed);
            }
        }

        // 绘制游戏
        this.draw();
    }

    draw() {
        // 清空画布
        this.ctx.fillStyle = COLORS.BACKGROUND;
        this.ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

        // 绘制网格
        this.drawGrid();

        // 绘制食物
        this.drawFood();

        // 绘制蛇
        this.drawSnake();

        // 如果暂停，绘制暂停界面
        if (this.state === GAME_STATE.PAUSED) {
            this.drawPauseScreen();
        }
    }

    drawGrid() {
        this.ctx.strokeStyle = COLORS.GRID;
        this.ctx.lineWidth = 0.5;

        // 绘制垂直线
        for (let x = 0; x <= CANVAS_WIDTH; x += GRID_SIZE) {
            this.ctx.beginPath();
            this.ctx.moveTo(x, 0);
            this.ctx.lineTo(x, CANVAS_HEIGHT);
            this.ctx.stroke();
        }

        // 绘制水平线
        for (let y = 0; y <= CANVAS_HEIGHT; y += GRID_SIZE) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, y);
            this.ctx.lineTo(CANVAS_WIDTH, y);
            this.ctx.stroke();
        }
    }

    drawSnake() {
        this.snake.segments.forEach((segment, index) => {
            const x = segment.x * GRID_SIZE;
            const y = segment.y * GRID_SIZE;

            // 蛇头用不同颜色
            if (index === 0) {
                this.ctx.fillStyle = COLORS.SNAKE_HEAD;
            } else {
                this.ctx.fillStyle = COLORS.SNAKE_BODY;
            }

            // 绘制圆角矩形
            this.roundRect(x + 1, y + 1, GRID_SIZE - 2, GRID_SIZE - 2, 4);

            // 绘制蛇眼睛（头部）
            if (index === 0) {
                this.ctx.fillStyle = '#FFFFFF';
                const eyeSize = GRID_SIZE / 5;

                // 根据方向调整眼睛位置
                let leftEyeX, leftEyeY, rightEyeX, rightEyeY;

                if (this.snake.direction === DIRECTION.RIGHT) {
                    leftEyeX = x + GRID_SIZE - eyeSize * 2;
                    leftEyeY = y + eyeSize * 2;
                    rightEyeX = x + GRID_SIZE - eyeSize * 2;
                    rightEyeY = y + GRID_SIZE - eyeSize * 3;
                } else if (this.snake.direction === DIRECTION.LEFT) {
                    leftEyeX = x + eyeSize;
                    leftEyeY = y + eyeSize * 2;
                    rightEyeX = x + eyeSize;
                    rightEyeY = y + GRID_SIZE - eyeSize * 3;
                } else if (this.snake.direction === DIRECTION.UP) {
                    leftEyeX = x + eyeSize * 2;
                    leftEyeY = y + eyeSize;
                    rightEyeX = x + GRID_SIZE - eyeSize * 3;
                    rightEyeY = y + eyeSize;
                } else { // DOWN
                    leftEyeX = x + eyeSize * 2;
                    leftEyeY = y + GRID_SIZE - eyeSize * 2;
                    rightEyeX = x + GRID_SIZE - eyeSize * 3;
                    rightEyeY = y + GRID_SIZE - eyeSize * 2;
                }

                this.ctx.beginPath();
                this.ctx.arc(leftEyeX, leftEyeY, eyeSize, 0, Math.PI * 2);
                this.ctx.fill();

                this.ctx.beginPath();
                this.ctx.arc(rightEyeX, rightEyeY, eyeSize, 0, Math.PI * 2);
                this.ctx.fill();
            }
        });
    }

    drawFood() {
        const x = this.food.position.x * GRID_SIZE;
        const y = this.food.position.y * GRID_SIZE;

        // 绘制食物（苹果形状）
        this.ctx.fillStyle = COLORS.FOOD;

        // 绘制苹果主体
        this.ctx.beginPath();
        this.ctx.ellipse(x + GRID_SIZE/2, y + GRID_SIZE/2, GRID_SIZE/2 - 2, GRID_SIZE/2 - 3, 0, 0, Math.PI * 2);
        this.ctx.fill();

        // 绘制苹果茎
        this.ctx.fillStyle = '#8B4513';
        this.ctx.fillRect(x + GRID_SIZE/2 - 1, y + 2, 2, 4);

        // 绘制苹果叶子
        this.ctx.fillStyle = '#228B22';
        this.ctx.beginPath();
        this.ctx.ellipse(x + GRID_SIZE/2 + 3, y + 3, 3, 2, Math.PI/4, 0, Math.PI * 2);
        this.ctx.fill();
    }

    drawPauseScreen() {
        // 半透明覆盖层
        this.ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        this.ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

        // 暂停文字
        this.ctx.fillStyle = COLORS.TEXT;
        this.ctx.font = 'bold 48px Arial';
        this.ctx.textAlign = 'center';
        this.ctx.textBaseline = 'middle';
        this.ctx.fillText('游戏暂停', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 - 30);

        this.ctx.font = '24px Arial';
        this.ctx.fillText('按空格键或点击"继续"按钮继续游戏', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2 + 30);
    }

    roundRect(x, y, width, height, radius) {
        this.ctx.beginPath();
        this.ctx.moveTo(x + radius, y);
        this.ctx.lineTo(x + width - radius, y);
        this.ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
        this.ctx.lineTo(x + width, y + height - radius);
        this.ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
        this.ctx.lineTo(x + radius, y + height);
        this.ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
        this.ctx.lineTo(x, y + radius);
        this.ctx.quadraticCurveTo(x, y, x + radius, y);
        this.ctx.closePath();
        this.ctx.fill();
    }

    updateScore() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('length').textContent = this.snake.segments.length + this.snake.growPending;
    }

    updateButtonStates() {
        const startBtn = document.getElementById('start-btn');
        const pauseBtn = document.getElementById('pause-btn');
        const resetBtn = document.getElementById('reset-btn');

        switch (this.state) {
            case GAME_STATE.MENU:
                startBtn.innerHTML = '<i class="fas fa-play"></i> 开始游戏';
