class Snake {
    constructor(canvas) {
        this.canvas = canvas;
        this.size = 20;
        this.speed = 150; // 毫秒
        this.direction = 'RIGHT';
        this.nextDirection = 'RIGHT';
        this.body = [
            { x: 100, y: 100 },
            { x: 80, y: 100 },
            { x: 60, y: 100 }
        ];
        this.growPending = 0;
    }

    get head() {
        return this.body[0];
    }

    changeDirection(newDirection) {
        // 防止反向移动
        const opposites = {
            'UP': 'DOWN',
            'DOWN': 'UP',
            'LEFT': 'RIGHT',
            'RIGHT': 'LEFT'
        };
        if (opposites[newDirection] !== this.direction) {
            this.nextDirection = newDirection;
        }
    }

    move() {
        this.direction = this.nextDirection;

        const newHead = { ...this.head };

        switch (this.direction) {
            case 'UP': newHead.y -= this.size; break;
            case 'DOWN': newHead.y += this.size; break;
            case 'LEFT': newHead.x -= this.size; break;
            case 'RIGHT': newHead.x += this.size; break;
        }

        this.body.unshift(newHead);

        if (this.growPending > 0) {
            this.growPending--;
        } else {
            this.body.pop();
        }
    }

    checkCollision() {
        // 检查墙壁碰撞
        if (this.head.x < 0 || this.head.x >= this.canvas.width ||
            this.head.y < 0 || this.head.y >= this.canvas.height) {
            return true;
        }

        // 检查自身碰撞
        for (let i = 1; i < this.body.length; i++) {
            if (this.head.x === this.body[i].x && this.head.y === this.body[i].y) {
