        document.getElementById('restart-btn').addEventListener('click', () => this.reset());
    }

    start() {
        if (this.isRunning) return;

        this.isRunning = true;
        this.isPaused = false;
        this.isGameOver = false;

        document.getElementById('start-btn').style.display = 'none';
        document.getElementById('pause-btn').innerHTML = '<i class="fas fa-pause"></i> 暂停';

        this.gameLoop();
    }

    gameLoop() {
        if (this.gameInterval) clearInterval(this.gameInterval);

        this.gameInterval = setInterval(() => {
            if (!this.isPaused && this.isRunning && !this.isGameOver) {
                this.update();
                this.draw();
            }
        }, this.gameSpeed);
    }

    update() {
        this.snake.move();

        // 检查碰撞
        if (this.snake.checkCollision()) {
            this.gameOver();
            return;
        }

        // 检查是否吃到食物
        if (this.snake.head.x === this.food.position.x && 
            this.snake.head.y === this.food.position.y) {
            this.snake.grow();
            this.food = new Food(this.canvas, this.snake);
            this.score += 10;
            this.updateScore();

            // 随着分数增加，游戏速度加快
            if (this.score % 50 === 0 && this.gameSpeed > 50) {
                this.gameSpeed -= 5;
                this.gameLoop();
            }
        }
    }

    draw() {
        // 清空画布
        this.ctx.fillStyle = '#2f3542';
        this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

        // 绘制网格
        this.ctx.strokeStyle = '#57606f';
        this.ctx.lineWidth = 0.5;
        for (let x = 0; x <= this.canvas.width; x += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(x, 0);
            this.ctx.lineTo(x, this.canvas.height);
            this.ctx.stroke();
        }
        for (let y = 0; y <= this.canvas.height; y += 20) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, y);
            this.ctx.lineTo(this.canvas.width, y);
            this.ctx.stroke();
        }

        // 绘制游戏元素
        this.food.draw(this.ctx);
        this.snake.draw(this.ctx);
    }

    updateScore() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('length').textContent = this.snake.body.length;

        if (this.score > this.highScore) {
            this.highScore = this.score;
            localStorage.setItem('snakeHighScore', this.highScore);
            document.getElementById('high-score').textContent = this.highScore;
        }
    }

    togglePause() {
        if (!this.isRunning || this.isGameOver) return;

        this.isPaused = !this.isPaused;
        const pauseBtn = document.getElementById('pause-btn');

        if (this.isPaused) {
            pauseBtn.innerHTML = '<i class="fas fa-play"></i> 继续';
            this.ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
            this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
            this.ctx.fillStyle = '#ffffff';
            this.ctx.font = '30px Arial';
            this.ctx.textAlign = 'center';
            this.ctx.fillText('游戏暂停', this.canvas.width / 2, this.canvas.height / 2);
        } else {
            pauseBtn.innerHTML = '<i class="fas fa-pause"></i> 暂停';
        }
    }

    gameOver() {
        this.isRunning = false;
        this.isGameOver = true;
        clearInterval(this.gameInterval);

        document.getElementById('game-over').style.display = 'block';
        document.getElementById('final-score').textContent = this.score;
        document.getElementById('start-btn').style.display = 'inline-block';
        document.getElementById('pause-btn').innerHTML = '<i class="fas fa-pause"></i> 暂停';
    }

    reset() {
        this.snake = new Snake(this.canvas);
        this.food = new Food(this.canvas, this.snake);
        this.score = 0;
        this.gameSpeed = 150;
        this.isPaused = false;
        this.isGameOver = false;
        this.isRunning = false;

        this.updateScore();
        document.getElementById('game-over').style.display = 'none';
        document.getElementById('start-btn').style.display = 'inline-block';
        document.getElementById('pause-btn').innerHTML = '<i class="fas fa-pause"></i> 暂停';

        this.draw();
    }
}

