<body>
    <h1>🐍 Snake Game</h1>

    <div id="score-board">
        <span>Score: <span id="score">0</span></span>
        <span>High Score: <span id="high-score">0</span></span>
    </div>

    <div id="game-container">
        <canvas id="game-canvas" width="400" height="400"></canvas>
        <div id="game-over">
            <h2>Game Over!</h2>
            <p>Final Score: <span id="final-score">0</span></p>
            <button id="restart-btn">Play Again</button>
        </div>
    </div>

    <div class="controls">
        Use arrow keys or WASD to move
    </div>

    <script>
        // Game constants
        const CANVAS_SIZE = 400;
        const TILE_SIZE = 20;
        const TILE_COUNT = CANVAS_SIZE / TILE_SIZE;
        const GAME_SPEED = 100; // milliseconds

        // Game state
        let snake = [];
        let food = {};
        let direction = { x: 1, y: 0 };
        let nextDirection = { x: 1, y: 0 };
        let score = 0;
        let highScore = localStorage.getItem('snakeHighScore') || 0;
        let gameInterval;
        let isGameOver = false;

        // DOM elements
        const canvas = document.getElementById('game-canvas');
        const ctx = canvas.getContext('2d');
        const scoreElement = document.getElementById('score');
        const highScoreElement = document.getElementById('high-score');
        const gameOverElement = document.getElementById('game-over');
        const finalScoreElement = document.getElementById('final-score');
        const restartBtn = document.getElementById('restart-btn');

        // Initialize high score display
        highScoreElement.textContent = highScore;

        // Initialize game
        function initGame() {
            // Reset game state
            snake = [
                { x: 5, y: 10 },
                { x: 4, y: 10 },
                { x: 3, y: 10 }
            ];
            direction = { x: 1, y: 0 };
            nextDirection = { x: 1, y: 0 };
            score = 0;
            isGameOver = false;

            scoreElement.textContent = score;
            gameOverElement.style.display = 'none';

            spawnFood();

            if (gameInterval) clearInterval(gameInterval);
            gameInterval = setInterval(gameLoop, GAME_SPEED);
        }

        // Spawn food at random position
        function spawnFood() {
            let validPosition = false;
            while (!validPosition) {
                food = {
                    x: Math.floor(Math.random() * TILE_COUNT),
                    y: Math.floor(Math.random() * TILE_COUNT)
                };

                // Check if food spawned on snake
                validPosition = !snake.some(segment => 
                    segment.x === food.x && segment.y === food.y
                );
            }
        }

        // Game loop
        function gameLoop() {
            if (isGameOver) return;

            // Update direction
            direction = nextDirection;

            // Calculate new head position
            const head = { 
                x: snake[0].x + direction.x, 
                y: snake[0].y + direction.y 
            };

            // Check for collisions
            if (checkCollision(head)) {
                gameOver();
                return;
            }

            // Add new head
            snake.unshift(head);

            // Check if food eaten
            if (head.x === food.x && head.y === food.y) {
                score += 10;
                scoreElement.textContent = score;
                spawnFood();
            } else {
                // Remove tail if no food eaten
                snake.pop();
            }

            // Draw everything
            draw();
        }

        // Check for collisions
        function checkCollision(head) {
            // Wall collision
            if (head.x < 0 || head.x >= TILE_COUNT || 
                head.y < 0 || head.y >= TILE_COUNT) {
                return true;
            }

            // Self collision
            for (let i = 1; i < snake.length; i++) {
                if (head.x === snake[i].x && head.y === snake[i].y) {
                    return true;
                }
            }

            return false;
        }

        // Draw game state
        function draw() {
            // Clear canvas
            ctx.fillStyle = '#34495e';
            ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

            // Draw snake
            snake.forEach((segment, index) => {
                // Head is green, body is slightly darker
                ctx.fillStyle = index === 0 ? '#2ecc71' : '#27ae60';
                ctx.fillRect(
                    segment.x * TILE_SIZE, 
                    segment.y * TILE_SIZE, 
                    TILE_SIZE - 2, 
                    TILE_SIZE - 2
                );

                // Add eyes to head
                if (index === 0) {
                    ctx.fillStyle = 'white';
                    const eyeSize = 4;
                    const eyeOffset = 4;

                    // Position eyes based on direction
                    if (direction.x === 1) { // Right
                        ctx.fillRect(
                            segment.x * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            segment.y * TILE_SIZE + eyeOffset,
                            eyeSize, eyeSize
                        );
                        ctx.fillRect(
                            segment.x * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            segment.y * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            eyeSize, eyeSize
                        );
                    } else if (direction.x === -1) { // Left
                        ctx.fillRect(
                            segment.x * TILE_SIZE + eyeOffset,
                            segment.y * TILE_SIZE + eyeOffset,
                            eyeSize, eyeSize
                        );
                        ctx.fillRect(
                            segment.x * TILE_SIZE + eyeOffset,
                            segment.y * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            eyeSize, eyeSize
                        );
                    } else if (direction.y === -1) { // Up
                        ctx.fillRect(
                            segment.x * TILE_SIZE + eyeOffset,
                            segment.y * TILE_SIZE + eyeOffset,
                            eyeSize, eyeSize
                        );
                        ctx.fillRect(
                            segment.x * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            segment.y * TILE_SIZE + eyeOffset,
                            eyeSize, eyeSize
                        );
                    } else { // Down
                        ctx.fillRect(
                            segment.x * TILE_SIZE + eyeOffset,
                            segment.y * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            eyeSize, eyeSize
                        );
                        ctx.fillRect(
                            segment.x * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            segment.y * TILE_SIZE + TILE_SIZE - eyeOffset - eyeSize,
                            eyeSize, eyeSize
                        );
                    }
                }
            });

            // Draw food
            ctx.fillStyle = '#e74c3c';
            ctx.beginPath();
            ctx.arc(
                food.x * TILE_SIZE + TILE_SIZE / 2,
                food.y * TILE_SIZE + TILE_SIZE / 2,
                TILE_SIZE / 2 - 2,
                0,
                Math.PI * 2
            );
            ctx.fill();
        }

        // Game over
        function gameOver() {
            isGameOver = true;
            clearInterval(gameInterval);

            // Update high score
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('snakeHighScore', highScore);
                highScoreElement.textContent = highScore;
            }

            finalScoreElement.textContent = score;
            gameOverElement.style.display = 'flex';
        }

        // Handle keyboard input
        document.addEventListener('keydown', (e) => {
            // Prevent default scrolling for arrow keys
            if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
                e.preventDefault();
            }

            switch (e.key) {
                case 'ArrowUp':
                case 'w':
                case 'W':
                    if (direction.y === 0) nextDirection = { x: 0, y: -1 };
                    break;
                case 'ArrowDown':
                case 's':
                case 'S':
                    if (direction.y === 0) nextDirection = { x: 0, y: 1 };
                    break;
                case 'ArrowLeft':
                case 'a':
                case 'A':
                    if (direction.x === 0) nextDirection = { x: -1, y: 0 };
                    break;
                case 'ArrowRight':
                case 'd':
                case 'D':
                    if (direction.x === 0) nextDirection = { x: 1, y: 0 };
                    break;
            }
        });

        // Restart button
        restartBtn.addEventListener('click', initGame);

        // Start the game
        initGame();
    </script>
</body>
</html>
